schema clinical_trial {
  enum TrialStatus { Recruit, Active, Completed, Withdrawn }

  entity Trial {
    id: ID
    title: String
    status: TrialStatus
    start_date: Date
    end_date: Option[Date]
  }

  entity Cohort {
    id: ID
    trial_id: Trial.id
    name: String
    description: Option[String]
  }

  entity Patient {
    id: ID
    first_name: String
    last_name: String
    date_of_birth: Date
  }

  entity Enrolment {
    id: ID
    patient_id: Patient.id
    cohort_id: Cohort.id
    enrolment_date: Date
    withdrawal_date: Option[Date]
  }

  enum EventType { AdverseEvent, SeriousAdverseEvent, ProtocolDeviation }

  entity TrialEvent {
    id: ID
    enrolment_id: Enrolment.id
    event_type: EventType
    description: String
    recorded_at: DateTime
  }

  service TrialService {
    create_trial(title: String, status: TrialStatus = Recruit, start_date: Date): Trial
    enrol_patient(patient_id: Patient.id, cohort_id: Cohort.id, enrolment_date: Date): Enrolment
    record_event(enrolment_id: Enrolment.id, event_type: EventType, description: String, recorded_at: DateTime = now()): TrialEvent
    find_events(): [TrialEvent]
  }
}

type BillingCadence {
  MONTHLY
  QUARTERLY
  ANNUAL
}

type Plan {
  id: ID!
  name: String!
  @Sensitive price: Decimal!
  billingCadence: BillingCadence!
}

type Subscriber {
  id: ID!
  name: String!
  email: String!
}

type Subscription {
  id: ID!
  subscriber: Subscriber!
  plan: Plan!
  startedAt: DateTime!
  renewedAt: DateTime
}

type Invoice {
  id: ID!
  subscription: Subscription!
  @Sensitive amount: Decimal!
  dueAt: DateTime!
}

service BillingService {
  subscribe(subscriberId: ID!, planId: ID!): Subscription!
  cancelSubscription(subscriptionId: ID!): Void
  generateInvoice(subscriptionId: ID!, dueAt: DateTime!): Invoice!
}
